# Discriminative: fixed small output (label / score)
def classify_email(text: str) -> str:
    features = embed(text)
    return "phishing" if score(features) > 0.9 else "legit"

# Generative: open-ended new content
def draft_reply(thread: str) -> str:
    prompt = f"Customer thread:\n{thread}\n\nDraft reply:"
    return sample_from_language_model(prompt, max_tokens=120)

def sentiment(text: str) -> float:
    """Discriminative: one scalar, no new text produced."""
    return float(model.predict_proba(text)["positive"])

